import React from 'react'
import { Paragraph, Row, ListSubSection, List, MarginBox } from '@fs/zion-ui'
import { ShadowScroller } from '@fs/zion-ui/quarks-authorized-use-only'
import { useTranslation } from 'react-i18next'
import BackButton from '../chat-buttons/BackButton'
import ChatPersonObject from '../chat-details/ChatPersonObject'
import { useChatState } from '../providers/ChatStateProvider'
import { chatVersion } from '../global/chatConfig'

export default function ChatBlockedContent({ isNarrow }) {
  const [t] = useTranslation()
  const { client } = useChatState()
  const mutedPersons = client?.mutedUsers?.map((mutedUser) => {
    return { user: mutedUser?.target }
  })

  return (
    <ShadowScroller>
      <MarginBox marginX="sm" marginY="sm" style={{ maxWidth: '500px', flex: 1 }}>
        <Row>
          {!isNarrow && <BackButton data-testid="close-blocked-users" />}
          <List growX>
            <ListSubSection heading={t('chat.blocked-users.heading', 'Blocked Users')}>
              {mutedPersons?.length < 1 && (
                <Paragraph size="sm">{t('chat.empty-section.heading', 'This section is empty.')}</Paragraph>
              )}
              {mutedPersons?.map((person) => {
                return <ChatPersonObject person={person} key={person.user.id} showMenu />
              })}
            </ListSubSection>
          </List>
        </Row>
      </MarginBox>
      <div style={{ marginInline: 8, opacity: 0.5 }}>
        <Paragraph size="xs">v{chatVersion}</Paragraph>
      </div>
    </ShadowScroller>
  )
}
